                  name="login"
                  prepend-icon="mdi-account"
                  type="text"
                  v-model="email"
                ></v-text-field>
                <v-text-field
                  v-model="password"
                  :append-icon="showPassword ? 'mdi-eye' : 'mdi-eye-off'"
                  outlined
                  rounded
                  dark
                  color="primary"
                  label="Пароль"
                  name="password"
                  prepend-icon="mdi-lock"
                  :type="showPassword ? 'text' : 'password'"
                  @click:append="showPassword = !showPassword"
                ></v-text-field>
              </v-form>
            </v-card-text>
            <v-card-actions class="login-actions">
              <v-btn
                class="my-3"
                block
                color="primary"
                depressed
                @click="auth"
                :loading="loading"
                >Войти</v-btn
              >
            </v-card-actions>
          </v-card>
