</template>
<script>
import { mapActions } from "vuex";
export default {
  metaInfo: {
    title: "Вход",
    titleTemplate: "%s | Панель управдения контентом",
  },
  data: () => ({
    showPassword: false,
    email: "",
    password: "",
    loading: false,
  }),
  methods: {
    ...mapActions("alerts", ["pushAlert"]),
    ...mapActions("auth", ["login"]),
    async auth() {
      try {
        this.loading = !this.loading;
        await this.login({
          email: this.email,
          password: this.password,
        });
        this.$router.push("/");
      } catch (e) {
        this.pushAlert({
          type: "error",
          content: e || "Произошла техническая ошибка",
        });
      } finally {
        this.loading = !this.loading;
      }
    },
  },
  beforeMount() {
    document.querySelector("html").style.overflow = "hidden";
  },
  beforeDestroy() {
    document.querySelector("html").style.overflow = "auto";
  },
};
</script>
